{
  "plan": {
    "root_causes": [
      {
        "hypothesis": "processEvent terminal block calls createBinder (returns string) and discards the return, so `binder` variable stays null and LaneState.binder is always null even after binder is created",
        "confidence": "high",
        "evidence": ["secretary.ts:619-621 — `let binder: Binder | null = null` then `yield* binderService.createBinder(...)` — no assignment", "secretary.ts:649 — `binder` passed to updated LaneState is null", "binder.ts:407 — createBinder returns `Effect.Effect<string>`, not `Binder`"]
      },
      {
        "hypothesis": "handleRoleOutput historian path calls finalizeBinder but never syncs the finalized binder back to lane.binder in activeLanes Ref",
        "confidence": "high",
        "evidence": ["secretary.ts:787 — `yield* binderService.finalizeBinder(laneId)` return value is discarded", "secretary.ts:111-126 — LaneState has `binder: CanonicalBinder | null` field that can become stale"]
      },
      {
        "hypothesis": "createLane calls createBinder but never populates lane.binder, leaving it null until the Ref is manually inspected",
        "confidence": "high",
        "evidence": ["secretary.ts:439 — `binder: null` in LaneState literal", "secretary.ts:447 — `yield* binderService.createBinder(...)` fire-and-forget"]
      },
      {
        "hypothesis": "addRoleEvidence uses generic `addEvidence(laneId, section, payload)` when binder.ts Interface already exports typed section-specific methods",
        "confidence": "medium",
        "evidence": ["secretary.ts:680-689 — section string switch", "secretary.ts:740 — `yield* binderService.addEvidence(laneId, section, evidencePayload)`", "binder.ts:148-169 — Interface already has addScoutReport, setArchitecturePlan, addCriticReview, addExecutionEvent, addValidationResult, addRedTeamFinding, setHandoffSummary"]
      }
    ],
    "fixes": [
      {
        "id": "fix-1",
        "description": "processEvent terminal block: use ensureBinder (returns Binder) and assign to `binder` variable",
        "files": ["packages/opencode/src/campaign/secretary.ts"],
        "before": "      let binder: Binder | null = null
      if (isTerminal(newState)) {
        yield* binderService.createBinder(laneId, lane.campaignId, lane.scope, lane.scope)
        for (const t of updatedTransitions) {",
        "after": "      let binder: Binder | null = null
      if (isTerminal(newState)) {
        binder = yield* binderService.ensureBinder(laneId, lane.campaignId, lane.scope, lane.scope)
        for (const t of updatedTransitions) {",
        "impact": {
          "affected_files": ["packages/opencode/src/campaign/secretary.ts"],
          "tests_to_run": ["packages/opencode/test/ — any test exercising processEvent with terminal states"]
        },
        "risks": [
          "ensureBinder returns stale state if binder already exists in cache (no re-evaluation of evidence events) — but createBinder was also a no-op on existing, so same behavior",
          "If binder creation fails (EventStore error), `binder` remains null — same as before, lane gets null binder"
        ],
        "validation": ["Verify `binder` is no longer null in updated LaneState after terminal processEvent", "Check that getLaneBinder/returnLane can retrieve the binder after terminal event"]
      },
      {
        "id": "fix-2",
        "description": "Add centralized finalizeLaneClosure function that wraps LaneReturned processEvent + finalizeBinder + binder sync",
        "files": ["packages/opencode/src/campaign/secretary.ts"],
        "before": "      // Historian: explicit closure sequence — evidence added first, then finalize after LaneReturned
      yield* addRoleEvidence(laneId, output)
      if (output.role === "historian") {
        const updatedLane = yield* ensureLane(laneId)
        if (updatedLane.currentState === "checkpointed") {
          yield* processEvent(laneId, { _tag: "LaneReturned", binderDigest: output.checkpointSha ?? "" })
          yield* binderService.finalizeBinder(laneId)
        }
      }",
        "after": "      // Historian: explicit closure sequence — evidence added first, then finalize after LaneReturned
      yield* addRoleEvidence(laneId, output)
      if (output.role === "historian") {
        yield* finalizeLaneClosure(laneId, output)
      }",
        "impact": {
          "affected_files": ["packages/opencode/src/campaign/secretary.ts"],
          "tests_to_run": ["Any test exercising handleRoleOutput with historian role"]
        },
        "risks": [
          "finalizeLaneClosure calls processEvent(LaneReturned) which triggers the terminal block again — ensureBinder is idempotent, but transitionEvents/executionEvents will be re-appended to binder (duplicate evidence risk)",
          "If checkpointed state check is moved into finalizeLaneClosure, ensure it still gates correctly"
        ],
        "validation": ["Verify historian closure sequence completes", "Check that binder is finalized and lane.binder is synced"]
      },
      {
        "id": "fix-3",
        "description": "Sync lane.binder shadow field after binder creation (createLane) and finalization (finalizeLaneClosure)",
        "files": ["packages/opencode/src/campaign/secretary.ts"],
        "before_createLane": "      yield* binderService.createBinder(id, campaignId, scope, scope)
    })",
        "after_createLane": "      yield* binderService.createBinder(id, campaignId, scope, scope)
      const freshBinder = yield* binderService.getBinder(id)
      if (Option.isSome(freshBinder)) {
        yield* Ref.update(activeLanes, (map) => {
          const next = new Map(map)
          const existing = next.get(id)
          if (existing) next.set(id, { ...existing, binder: freshBinder.value })
          return next
        })
      }
    })",
        "impact": {
          "affected_files": ["packages/opencode/src/campaign/secretary.ts"],
          "tests_to_run": ["Any test exercising createLane or getLaneBinder"]
        },
        "risks": [
          "Ref.update is atomic but the pattern of get-then-update (getBinder then Ref.update) has a read-write gap — binder could change between getBinder and Ref.update",
          "Mitigation: the gap is minimal since this runs synchronously in createLane — no concurrent access expected during lane creation"
        ],
        "validation": ["Verify lane.binder is populated after createLane", "Check getLaneBinder returns binder without falling back to lane.binder"]
      },
      {
        "id": "fix-4",
        "description": "Replace generic addEvidence in addRoleEvidence with typed methods; add missing typed methods to binder.ts Interface",
        "files": ["packages/opencode/src/campaign/binder.ts", "packages/opencode/src/campaign/secretary.ts"],
        "subfixes": [
          {
            "label": "fix-4a: Add typed methods to binder.ts Interface (addTransitionEvidence, setApprovedPlan)",
            "file": "packages/opencode/src/campaign/binder.ts",
            "location": "Interface definition, after line 164 (after setHandoffSummary)",
            "insert": [
              "  readonly addTransitionEvidence: (laneId: string, ref: EventRef) => Effect.Effect<void, BinderError>",
              "  readonly setApprovedPlan: (laneId: string, ref: ArtifactRef) => Effect.Effect<void, BinderError>",
              "  readonly addRepairEvidence: (laneId: string, ref: EventRef) => Effect.Effect<void, BinderError>"
            ]
          },
          {
            "label": "fix-4b: Implement new typed methods in binder.ts make()",
            "file": "packages/opencode/src/campaign/binder.ts",
            "location": "After setHandoffSummary implementation (~line 569), before updateStatus",
            "insert": [
              "  const addTransitionEvidence = Effect.fn("Binder.addTransitionEvidence")(function* (laneId: string, ref: EventRef) {",
              "    return yield* addEvidence(laneId, "transitionEvents", ref)",
              "  })",
              "  const setApprovedPlan = Effect.fn("Binder.setApprovedPlan")(function* (laneId: string, ref: ArtifactRef) {",
              "    return yield* addEvidence(laneId, "approvedPlan", ref)",
              "  })",
              "  const addRepairEvidence = Effect.fn("Binder.addRepairEvidence")(function* (laneId: string, ref: EventRef) {",
              "    return yield* addEvidence(laneId, "repairHistory", ref)",
              "  })"
            ]
          },
          {
            "label": "fix-4c: Export new methods in make() return block",
            "file": "packages/opencode/src/campaign/binder.ts",
            "location": "In the return Service.of({...}) block, add entries",
            "insert_after": ["setHandoffSummary,"],
            "insert": ["    addTransitionEvidence,", "    setApprovedPlan,", "    addRepairEvidence,"]
          },
          {
            "label": "fix-4d: Replace addRoleEvidence section switch with typed method calls",
            "file": "packages/opencode/src/campaign/secretary.ts",
            "location": "addRoleEvidence function, lines ~680-740",
            "before": "      const section = (() => {
        switch (output.role) {
          case "scout": case "cartographer": return "scoutReports"
          case "architect": return "architecturePlan"
          case "critic": return "criticReviews"
          case "executor": return "executionEvents"
          case "validator": return "validationResults"
          case "redteam": return "redTeamFindings"
          case "historian": return "handoffSummary"
          default: return "roleOutput"
        }
      })()

      // Build correct payload type per section category
      const evidencePayload = (() => {
        switch (output.role) {
          case "scout":
          case "cartographer":
          case "architect":
          case "critic":
            // ArtifactRef sections: scoutReports, architecturePlan, criticReviews
            return {
              type: output.role,
              path: `lane:${laneId}:${output.role.toLowerCase()}:${now()}`,
              summary: output.message,
              contentDigest: "",
            }
          case "executor":
            // EventRef section: executionEvents
            return {
              eventId: `${laneId}:executor:${now()}`,
              eventType: "executor",
              ts: new Date().toISOString(),
              summary: output.message,
            }
          case "validator":
            // ValidationResult section: validationResults
            return {
              tool: "validator",
              status: output.passed ? "pass" : "fail",
              failures: output.failedTests.map((i) => ({ name: i, message: i })),
              durationMs: 0,
              afterLastEdit: true,
            }
          case "redteam":
            // EventRef section: redTeamFindings
            return {
              eventId: `${laneId}:redteam:${now()}`,
              eventType: "redteam",
              ts: new Date().toISOString(),
              summary: `Red team: ${output.findings.length} findings`,
            }
          case "historian":
            // string section: handoffSummary
            return {
              eventId: `${laneId}:historian:${now()}`,
              eventType: "historian",
              ts: new Date().toISOString(),
              summary: `Checkpoint: ${output.checkpointSha}`,
            }
        }
      })()
      if (evidencePayload) {
        yield* binderService.addEvidence(laneId, section, evidencePayload)
      }
      if (output.role === "critic" && output.verdict === "approved") {
        yield* binderService.addEvidence(laneId, "approvedPlan", {
          type: "critic:approved",
          path: `lane:${laneId}:critic:approved:${now()}`,
          summary: "Plan approved by critic review",
          contentDigest: "",
        })
      }",
            "after": "      if (output.role === "scout" || output.role === "cartographer") {
        yield* binderService.addScoutReport(laneId, {
          type: output.role,
          path: `lane:${laneId}:${output.role.toLowerCase()}:${now()}`,
          summary: output.message,
          contentDigest: "",
        })
      } else if (output.role === "architect") {
        yield* binderService.setArchitecturePlan(laneId, {
          type: "architect",
          path: `lane:${laneId}:architect:${now()}`,
          summary: output.message,
          contentDigest: "",
        })
      } else if (output.role === "critic") {
        yield* binderService.addCriticReview(laneId, {
          type: "critic",
          path: `lane:${laneId}:critic:${now()}`,
          summary: output.message,
          contentDigest: "",
        })
        if (output.verdict === "approved") {
          yield* binderService.setApprovedPlan(laneId, {
            type: "critic:approved",
            path: `lane:${laneId}:critic:approved:${now()}`,
            summary: "Plan approved by critic review",
            contentDigest: "",
          })
        }
      } else if (output.role === "executor") {
        yield* binderService.addExecutionEvent(laneId, {
          eventId: `${laneId}:executor:${now()}`,
          eventType: "executor",
          ts: new Date().toISOString(),
          summary: output.message,
        })
      } else if (output.role === "validator") {
        yield* binderService.addValidationResult(laneId, {
          type: "validation",
          path: `lane:${laneId}:validator:${now()}`,
          verdict: output.passed ? "pass" : "fail",
          findings: output.failedTests.map((i) => ({ severity: "major", summary: i })),
          contentDigest: "",
        })
      } else if (output.role === "redteam") {
        yield* binderService.addRedTeamFinding(laneId, {
          type: "redteam",
          severity: "major",
          summary: `Red team: ${output.findings.length} findings`,
          evidenceRef: `lane:${laneId}:redteam:${now()}`,
        })
      } else if (output.role === "historian") {
        yield* binderService.setHandoffSummary(laneId, output.checkpointSha ?? output.message)
      }"
          },
          {
            "label": "fix-4e: Replace addEvidence in processEvent terminal block with typed methods",
            "file": "packages/opencode/src/campaign/secretary.ts",
            "location": "processEvent terminal block, lines ~625-643",
            "before": "        for (const t of updatedTransitions) {
          yield* binderService.addEvidence(
            laneId,
            "transitionEvents",
            {
              eventId: `${laneId}:${t.event}:${t.timestamp}`,
              eventType: t.event,
              ts: new Date(t.timestamp).toISOString(),
              summary: `Transition: ${t.from} → ${t.to}`,
            },
          )
        }
        yield* binderService.addEvidence(
          laneId,
          "executionEvents",
          {
            eventId: `${laneId}:${event._tag}:${now()}`,
            eventType: event._tag,
            ts: new Date().toISOString(),
            summary: `Event: ${event._tag}`,
          },
        )",
            "after": "        for (const t of updatedTransitions) {
          yield* binderService.addTransitionEvidence(laneId, {
            eventId: `${laneId}:${t.event}:${t.timestamp}`,
            eventType: t.event,
            ts: new Date(t.timestamp).toISOString(),
            summary: `Transition: ${t.from} → ${t.to}`,
          })
        }
        yield* binderService.addExecutionEvent(laneId, {
          eventId: `${laneId}:${event._tag}:${now()}`,
          eventType: event._tag,
          ts: new Date().toISOString(),
          summary: `Event: ${event._tag}`,
        })"
          }
        ],
        "impact": {
          "affected_files": ["packages/opencode/src/campaign/binder.ts", "packages/opencode/src/campaign/secretary.ts"],
          "tests_to_run": ["Any test exercising addRoleEvidence or processEvent with terminal states"]
        },
        "risks": [
          "Type mismatch: addRoleEvidence's validator payload has `{tool, status, failures, durationMs, afterLastEdit}` but ValidationResult expects `{type, path, verdict, findings, contentDigest}` — fix transforms the payload to match",
          "Type mismatch: addRoleEvidence's redteam payload has `{eventId, eventType, ts, summary}` but RedTeamFinding expects `{type, severity, summary, evidenceRef}` — fix transforms the payload to match",
          "setHandoffSummary takes `string` but the old code passed an object — fix passes `output.checkpointSha ?? output.message` as a string",
          "The `knownSections` check in addEvidence is bypassed when using typed methods — but that's intentional since typed methods hardcode the correct section"
        ],
        "validation": ["Run pyright to verify type compatibility", "Verify all evidence paths still record correctly"]
      }
    ],
    "new_function": {
      "name": "finalizeLaneClosure",
      "file": "packages/opencode/src/campaign/secretary.ts",
      "location": "Insert after addRoleEvidence function (after line ~755), before handleRoleOutput",
      "body": "  function finalizeLaneClosure(laneId: string, output: RoleOutput): Effect.Effect<void, BinderError | LaneNotFoundError> {
    return Effect.gen(function* () {
      const lane = yield* ensureLane(laneId)
      if (lane.currentState !== "checkpointed") return

      yield* processEvent(laneId, { _tag: "LaneReturned", binderDigest: output.checkpointSha ?? "" } satisfies RuntimeEvent)
      const finalized = yield* binderService.finalizeBinder(laneId)

      yield* Ref.update(activeLanes, (map) => {
        const next = new Map(map)
        const existing = next.get(laneId)
        if (existing) next.set(laneId, { ...existing, binder: finalized })
        return next
      })
    })
  }"
    },
    "apply_order": ["fix-1", "fix-2 ({new_function})", "fix-3", "fix-4"],
    "rollback_plan": "Revert each fix in reverse order: restore addEvidence calls, remove finalizeLaneClosure, restore createBinder call, restore binder sync removal"
  }
}
